import React from 'react';
import { Link } from 'react-router-dom';

const Login = () => {
  return (
    <div className="font-display bg-background-light dark:bg-background-dark min-h-screen flex flex-col items-center justify-center p-4">
      <div className="w-full max-w-md bg-white dark:bg-slate-900 rounded-xl shadow-xl border border-slate-200 dark:border-slate-800 overflow-hidden">
        <div className="p-8">
          <div className="text-center mb-8">
            <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Welcome Back</h1>
          </div>
          <form className="space-y-5">
            <input className="w-full p-3 bg-slate-50 dark:bg-slate-800 border rounded-lg" placeholder="University Email" type="email" />
            <input className="w-full p-3 bg-slate-50 dark:bg-slate-800 border rounded-lg" placeholder="Password" type="password" />
            <button className="w-full bg-primary text-white font-bold py-3 rounded-lg shadow-md hover:bg-primary/90">Sign In</button>
          </form>
          <div className="mt-8 text-center text-sm text-slate-600">
            Don't have an account? <Link to="/register" className="text-primary font-bold hover:underline">Register here</Link>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
